mapper.select:
		/*
             SQL ID : LessonStudyMemoDAO.select
             	설  명 : 학습메모 정보 조회
         */

         AND A.ATNDLC_MEMO_ID = #{studyMemoId}

		/*
             SQL ID : LessonStudyMemoDAO.list
             	설  명 : 학습메모 목록 조회
         */


         	AND A.STD_ID = #{stdNo}


         	AND A.USER_ID = #{userId}


         	AND A.SBJCT_ID = #{crsCreCd}

         ORDER BY A.FRST_INQ_DTTM DESC

		/*
             SQL ID : LessonStudyMemoDAO.listPaging
             	설  명 : 학습메모 목록 조회 페이징
         */



         	AND A.USER_ID = #{userId}


         	AND A.STD_ID = #{stdNo}


         	AND A.SBJCT_ID = #{crsCreCd}


         	AND (
         		LOWER(A.MEMO_CTS) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
         	)

         ORDER BY A.FRST_INQ_DTTM DESC

mapper.insert:
		/*
             SQL ID : LessonStudyMemoDAO.insert
             	설  명 : 학습메모 등록
         */
         INSERT INTO TB_LMS_ATNDLC_MEMO (
         	  ATNDLC_MEMO_ID
			, STD_ID
			, USER_ID
			, SBJCT_ID
			, LCTR_SCHDL_ID
			, SBJCT_LCTR_CONTS_ID
			, RCNT_ATNDLC_PSTN
			, MEMO_TTL
			, MEMO_CTS
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
         ) VALUES (
         	  #{studyMemoId}
         	, #{stdNo}
         	, #{userId}
         	, #{crsCreCd}
         	, #{lessonScheduleId}
         	, #{lessonCntsId}
         	, #{studySessionLoc}
         	, #{memoTitle}
         	, #{memoCnts}
         	, #{rgtrId}
         	, FN_DTTM()
         	, #{mdfrId}
         	, FN_DTTM()
         )

mapper.update:
		/*
             SQL ID : LessonStudyMemoDAO.update
             	설  명 : 학습메모 수정
         */
         UPDATE TB_LMS_ATNDLC_MEMO SET
         	  MDFR_ID = #{mdfrId}
         	, MOD_DTTM = FN_DTTM()

         	, MEMO_TTL = #{memoTitle}


         	, MEMO_CTS = #{memoCnts}

          WHERE ATNDLC_MEMO_ID = #{studyMemoId}

mapper.delete:
		/*
             SQL ID : LessonStudyMemoDAO.delete
             	설  명 : 학습메모 삭제
         */
         DELETE FROM TB_LMS_ATNDLC_MEMO
          WHERE ATNDLC_MEMO_ID = #{studyMemoId}
